) {
  // Clone the response to read the body safely
  const clonedResponse = response.clone();
  const bodyText = await clonedResponse.text();

  // Base64 encode the body text
  // In Zuplo/Cloudflare Workers environment, btoa is usually available.
  // We use the response body text to generate the signature.
  const signature = btoa(bodyText);

  // Create new headers as the original might be immutable
  const newHeaders = new Headers(response.headers);
  newHeaders.set("X-Signature", signature);

  // Return a new response with the original body and updated headers
  // We use response.body which is a ReadableStream
  return new Response(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers: newHeaders,
  });
}

